// src/pages/cleaner/CleanerPortal.jsx
import React, { useState, useEffect, useRef, useCallback } from 'react';
import { useApp } from '../../App';
import { timeAgo } from '../../utils/helpers';
import {
  Camera, MapPin, CheckCircle2, Clock, RotateCcw, X, ZoomIn, Bell, Trash2, Package, FlaskConical, Recycle, Droplets, AlertTriangle, ChevronLeft
} from 'lucide-react';

const C = {
  navy:'#0A1628', blue:'#1565C0', blueL:'#E3F2FD', green:'#2E7D32', greenL:'#E8F5E9',
  red:'#B71C1C', redL:'#FFEBEE', amber:'#E65100', amberL:'#FFF3E0', purple:'#4527A0', purpleL:'#EDE7F6',
  gray:'#546E7A', grayL:'#ECEFF1', text:'#0D1117', text2:'#3D4F61', text3:'#7A8FA6',
  white:'#fff', surface:'#F7F9FC', border:'#DDE3E9',
};

const GTYPE_ICONS = {
  'Plastic Waste': Trash2, 'Food Waste': Package, 'Abandoned Item': Package,
  'Chemical Spill': FlaskConical, 'Recyclable Waste': Recycle, 'Sewage / Water': Droplets,
};

// Logged-in Cleaner static profile reference
const CLEANER_ME = { id: 'c1', name: 'Dinesh Rao', area: 'Platform 1–3' };

const TopBar = ({ title, onBack, right }) => (
  <div style={{ display: 'flex', alignItems: 'center', gap: 10, padding: '12px 16px', borderBottom: `1px solid ${C.border}`, background: C.white, flexShrink: 0 }}>
    {onBack && <button onClick={onBack} style={{ width: 34, height: 34, borderRadius: '50%', background: C.surface, border: `1px solid ${C.border}`, display: 'flex', alignItems: 'center', justifyContent: 'center', cursor: 'pointer' }}><ChevronLeft size={18} color={C.text2} /></button>}
    <span style={{ fontSize: 15, fontWeight: 700, flex: 1, color: C.text }}>{title}</span>
    {right}
  </div>
);

function CleanedCamera({ onCapture, onBack }) {
  const videoRef = useRef(null);
  const canvasRef = useRef(null);
  const streamRef = useRef(null);
  const [ready, setReady] = useState(false);
  const [err, setErr] = useState(null);
  const [facing, setFacing] = useState('environment');
  const [flash, setFlash] = useState(false);

  const startCam = useCallback(async (f) => {
    try {
      if (streamRef.current) streamRef.current.getTracks().forEach(t => t.stop());
      const s = await navigator.mediaDevices.getUserMedia({ video: { facingMode: f, width: { ideal: 1280 }, height: { ideal: 720 } }, audio: false });
      streamRef.current = s;
      if (videoRef.current) { videoRef.current.srcObject = s; await videoRef.current.play(); setReady(true); setErr(null); }
    } catch (e) {
      setErr('Camera permission denied or device not found.');
    }
  }, []);

  useEffect(() => { startCam(facing); return () => { if (streamRef.current) streamRef.current.getTracks().forEach(t => t.stop()); }; }, [facing, startCam]);

  const shoot = () => {
    if (!ready || !canvasRef.current || !videoRef.current) return;
    setFlash(true); setTimeout(() => setFlash(false), 150);
    const v = videoRef.current, c = canvasRef.current;
    c.width = v.videoWidth || 1280; c.height = v.videoHeight || 720;
    const ctx = c.getContext('2d');
    if (facing === 'user') { ctx.translate(c.width, 0); ctx.scale(-1, 1); }
    ctx.drawImage(v, 0, 0, c.width, c.height);
    const url = c.toDataURL('image/jpeg', 0.85);
    if (streamRef.current) streamRef.current.getTracks().forEach(t => t.stop());
    onCapture(url);
  };

  return (
    <div style={{ display: 'flex', flexDirection: 'column', flex: 1, background: '#000', height: '100vh', overflow: 'hidden', position: 'fixed', inset: 0, zIndex: 999 }}>
      <canvas ref={canvasRef} style={{ display: 'none' }} />
      <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', padding: '16px', position: 'absolute', top: 0, left: 0, right: 0, zIndex: 10, background: 'linear-gradient(to bottom,rgba(0,0,0,.7),transparent)' }}>
        <button onClick={onBack} style={{ width: 36, height: 36, borderRadius: '50%', background: 'rgba(0,0,0,.5)', border: 'none', display: 'flex', alignItems: 'center', justifyContent: 'center', cursor: 'pointer' }}><X size={18} color="#fff" /></button>
        <div style={{ background: C.green, padding: '6px 14px', borderRadius: 99, fontSize: 12, fontWeight: 600, color: '#fff', display: 'flex', alignItems: 'center', gap: 5 }}>
          <Camera size={14} /> Take After-Clean Snap
        </div>
        <div style={{ width: 36 }} />
      </div>

      <div style={{ flex: 1, position: 'relative', overflow: 'hidden' }}>
        {flash && <div style={{ position: 'absolute', inset: 0, background: '#fff', zIndex: 20, opacity: 0.9 }} />}
        {err ? (
          <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', height: '100%', gap: 12, padding: 24 }}>
            <AlertTriangle size={32} color={C.amber} />
            <div style={{ color: '#fff', fontSize: 13 }}>{err}</div>
          </div>
        ) : (
          <video ref={videoRef} playsInline muted style={{ width: '100%', height: '100%', objectFit: 'cover' }} />
        )}
      </div>

      <div style={{ background: '#111', padding: '20px', display: 'flex', justifyContent: 'center', alignItems: 'center' }}>
        <button onClick={shoot} disabled={!ready || !!err} style={{ width: 68, height: 68, borderRadius: '50%', background: '#fff', border: 'none', display: 'flex', alignItems: 'center', justifyContent: 'center', cursor: 'pointer' }}>
          <div style={{ width: 54, height: 54, borderRadius: '50%', background: C.green }} />
        </button>
      </div>
    </div>
  );
}

function ConfirmCleaned({ complaint, cleanedPhoto, onConfirm, onRetake }) {
  return (
    <div style={{ display: 'flex', flexDirection: 'column', height: '100vh', background: C.surface }}>
      <TopBar title="Verification Dashboard" onBack={onRetake} />
      <div style={{ flex: 1, overflowY: 'auto', padding: 16 }}>
        
        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 10, marginBottom: 16 }}>
          <div style={{ background: '#fff', borderRadius: 12, overflow: 'hidden', border: `1px solid ${C.border}` }}>
            <div style={{ fontSize: 11, fontWeight: 700, padding: 6, textAlign: 'center', background: C.grayL }}>BEFORE WORK</div>
            <img src={complaint.image} alt="Before" style={{ width: '100%', height: 130, objectFit: 'cover' }} />
          </div>
          <div style={{ background: '#fff', borderRadius: 12, overflow: 'hidden', border: `1px solid ${C.green}` }}>
            <div style={{ fontSize: 11, fontWeight: 700, padding: 6, textAlign: 'center', background: C.greenL, color: C.green }}>AFTER CLEANED</div>
            <img src={cleanedPhoto} alt="After" style={{ width: '100%', height: 130, objectFit: 'cover' }} />
          </div>
        </div>

        <div style={{ background: '#fff', padding: 14, borderRadius: 12, border: `1px solid ${C.border}` }}>
          <div style={{ fontSize: 14, fontWeight: 700, marginBottom: 4 }}>{complaint.area}</div>
          <div style={{ fontSize: 12, color: C.text3, marginBottom: 8 }}>Category: {complaint.gtype}</div>
          <div style={{ fontSize: 12, color: C.text2, fontStyle: 'italic' }}>"Once submitted, your manager will counter-verify this placement picture live."</div>
        </div>
      </div>

      <div style={{ padding: 16, background: '#fff', borderTop: `1px solid ${C.border}`, display: 'flex', gap: 10 }}>
        <button onClick={onRetake} style={{ flex: 1, padding: 12, borderRadius: 10, border: `1px solid ${C.border}`, background: '#fff', fontWeight: 600, cursor: 'pointer' }}>Retake</button>
        <button onClick={() => onConfirm(cleanedPhoto)} style={{ flex: 2, padding: 12, borderRadius: 10, border: 'none', background: C.green, color: '#fff', fontWeight: 700, cursor: 'pointer' }}>Send Verification Proof</button>
      </div>
    </div>
  );
}

export default function CleanerPortal() {
  const { complaints, updateComplaint } = useApp();
  const [activeTask, setActiveTask] = useState(null);
  const [screen, setScreen] = useState('tasks'); // tasks | camera | confirm
  const [cleanedPhoto, setCleanedPhoto] = useState(null);

  // Sirf wahi tasks fetch karein jo Rajesh Kumar dwara is cleaner ko allot hue hain
  const myTasks = complaints.filter(c => c.assignedTo === CLEANER_ME.name && c.status === 'ASSIGNED_TO_CLEANER');
  const doneTasks = complaints.filter(c => c.assignedTo === CLEANER_ME.name && ['CLEANED_BY_FORCE', 'COMPLETED'].includes(c.status));

  const handleConfirm = async (photoDataUrl) => {
    await updateComplaint(activeTask.id, {
      status: 'CLEANED_BY_FORCE',
      cleanerStatus: 'WAITING_APPROVAL',
      cleanerPhoto: photoDataUrl 
    });
    setScreen('tasks');
    setActiveTask(null);
    setCleanedPhoto(null);
    alert("Proof image successfully transmitted to vendor's dashboard panel!");
  };

  if (screen === 'camera') return <CleanedCamera onCapture={(url) => { setCleanedPhoto(url); setScreen('confirm'); }} onBack={() => setScreen('tasks')} />;
  if (screen === 'confirm') return <ConfirmCleaned complaint={activeTask} cleanedPhoto={cleanedPhoto} onConfirm={handleConfirm} onRetake={() => setScreen('camera')} />;

  return (
    <div style={{ minHeight: '100vh', background: C.surface, fontFamily: 'system-ui,sans-serif' }}>
      <div style={{ background: `linear-gradient(135deg,${C.navy},#1a3a6e)`, padding: '16px 18px', color: '#fff' }}>
        <div style={{ fontSize: '16px', fontWeight: 800 }}>🦺 {CLEANER_ME.name} (Field Agent)</div>
        <div style={{ fontSize: '11px', color: 'rgba(255,255,255,0.6)' }}>Assigned Zone: {CLEANER_ME.area}</div>
      </div>

      <div style={{ padding: 16, maxWidth: 480, margin: '0 auto' }}>
        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 10, marginBottom: 16 }}>
          <div style={{ background: '#fff', padding: 12, borderRadius: 10, border: `1px solid ${C.border}` }}>
            <div style={{ fontSize: 10, color: C.text3, fontWeight: 700 }}>PENDING JOBS</div>
            <div style={{ fontSize: 20, fontWeight: 800, color: C.amber }}>{myTasks.length}</div>
          </div>
          <div style={{ background: '#fff', padding: 12, borderRadius: 10, border: `1px solid ${C.border}` }}>
            <div style={{ fontSize: 10, color: C.text3, fontWeight: 700 }}>FINISHED TODAY</div>
            <div style={{ fontSize: 20, fontWeight: 800, color: C.green }}>{doneTasks.length}</div>
          </div>
        </div>

        <div style={{ fontSize: 13, fontWeight: 700, marginBottom: 10 }}>My Cleaning Schedules ({myTasks.length})</div>

        {myTasks.length === 0 ? (
          <div style={{ background: '#fff', padding: 30, borderRadius: 12, textAlign: 'center', color: C.text3, border: `1px solid ${C.border}` }}>
            🎉 Standby State! No fresh cleaning tracks redirected to you.
          </div>
        ) : (
          myTasks.map(task => {
            const TypeIcon = GTYPE_ICONS[task.gtype] || Trash2;
            return (
              <div key={task.id} style={{ background: '#fff', border: `1px solid ${C.border}`, borderRadius: 14, overflow: 'hidden', marginBottom: 12 }}>
                <div style={{ height: 110, background: '#111' }}>
                  <img src={task.image} alt="Reported spot" style={{ width: '100%', height: '100%', objectFit: 'cover' }} />
                </div>
                <div style={{ padding: 12 }}>
                  <div style={{ fontSize: 13, fontWeight: 700 }}>{task.area} — {task.gtype}</div>
                  <div style={{ fontSize: 11, color: C.text3, marginBottom: 10 }}>📍 Reported {timeAgo(task.reportedAt)}</div>
                  
                  <button onClick={() => { setActiveTask(task); setScreen('camera'); }} style={{ width: '100%', background: C.blue, color: '#fff', border: 'none', padding: '10px', borderRadius: 8, fontWeight: 700, cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 6 }}>
                    <Camera size={14} /> Start Cleaning & Take Photo
                  </button>
                </div>
              </div>
            );
          })
        )}
      </div>
    </div>
  );
}
